#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return *(char*)a - *(char*)b;
}

int is_dynamic(char *s) {
    int len = strlen(s);
    int freq[26] = {0};
    for (int i = 0; i < len; i++) {
        freq[s[i] - 'a']++;
    }
    int unique = 0;
    for (int i = 0; i < 26; i++) {
        if (freq[i] > 0) unique++;
    }
    if (unique < 3) return 1;
    char *unique_chars = (char*)malloc(unique * sizeof(char));
    int k = 0;
    for (int i = 0; i < 26; i++) {
        if (freq[i] > 0) unique_chars[k++] = 'a' + i;
    }
    qsort(unique_chars, unique, sizeof(char), compare);
    int *perm = (int*)malloc(unique * sizeof(int));
    for (int i = 0; i < unique; i++) perm[i] = i;
    do {
        int *f = (int*)malloc(unique * sizeof(int));
        for (int i = 0; i < unique; i++) f[i] = freq[unique_chars[perm[i]] - 'a'];
        int valid = 1;
        for (int i = 2; i < unique; i++) {
            if (f[i] != f[i-1] + f[i-2]) {
                valid = 0;
                break;
            }
        }
        free(f);
        if (valid) return 1;
    } while (next_permutation(perm, unique));
    free(perm);
    free(unique_chars);
    return 0;
}

int next_permutation(int *arr, int n) {
    int i = n - 2;
    while (i >= 0 && arr[i] >= arr[i+1]) i--;
    if (i < 0) return 0;
    int j = n - 1;
    while (arr[j] <= arr[i]) j--;
    int temp = arr[i];
    arr[i] = arr[j];
    arr[j] = temp;
    int left = i + 1;
    int right = n - 1;
    while (left < right) {
        temp = arr[left];
        arr[left] = arr[right];
        arr[right] = temp;
        left++;
        right--;
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[100005];
        scanf("%s", s);
        if (is_dynamic(s)) printf("Dynamic\n");
        else printf("Not\n");
    }
    return 0;
}

