from itertools import permutations

def is_dynamic(s):
    freq = [0] * 26
    for c in s:
        freq[ord(c) - ord('a')] += 1
    unique = sum(1 for f in freq if f > 0)
    if unique < 3:
        return True
    unique_chars = [chr(i + ord('a')) for i, f in enumerate(freq) if f > 0]
    for p in permutations(unique_chars):
        f = [freq[ord(c) - ord('a')] for c in p]
        if all(f[i] == f[i-1] + f[i-2] for i in range(2, len(f))):
            return True
    return False

T = int(input())
for _ in range(T):
    s = input()
    if is_dynamic(s):
        print('Dynamic')
    else:
        print('Not')

