const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function isDynamic(s) {
    const freq = new Array(26).fill(0);
    for (let c of s) {
        freq[c.charCodeAt(0) - 'a'.charCodeAt(0)]++;
    }
    let unique = 0;
    for (let f of freq) {
        if (f > 0) unique++;
    }
    if (unique < 3) return true;
    const uniqueChars = [];
    for (let i = 0; i < 26; i++) {
        if (freq[i] > 0) uniqueChars.push(String.fromCharCode('a'.charCodeAt(0) + i));
    }
    const perms = permute(uniqueChars);
    for (let p of perms) {
        const f = p.map(c => freq[c.charCodeAt(0) - 'a'.charCodeAt(0)]);
        if (f.slice(2).every((v, i) => v === f[i] + f[i + 1])) return true;
    }
    return false;
}

function permute(arr) {
    if (arr.length === 1) return [arr];
    const result = [];
    for (let i = 0; i < arr.length; i++) {
        const rest = arr.slice(0, i).concat(arr.slice(i + 1));
        for (let p of permute(rest)) {
            result.push([arr[i]].concat(p));
        }
    }
    return result;
}

const T = parseInt(lines[idx++]);
for (let i = 0; i < T; i++) {
    const s = lines[idx++];
    if (isDynamic(s)) console.log('Dynamic');
    else console.log('Not');
}
